import React, { useEffect, useState } from 'react';
import api from '../axios';
import TaskCard from '../components/TaskCard';

export default function Dashboard() {
  const [items, setItems] = useState([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [query, setQuery] = useState('');
  const [status, setStatus] = useState('all');
  const [priority, setPriority] = useState('all');
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(12);
  const [sort, setSort] = useState('createdAt');
  const [order, setOrder] = useState('desc');

  async function loadTasks() {
    setLoading(true);
    const { data } = await api.get('/tasks', {
      params: {
        q: query || undefined,
        status: status !== 'all' ? status : undefined,
        priority: priority !== 'all' ? priority : undefined,
        page,
        limit,
        sort,
        order,
      },
    });
    setItems(data.items);
    setTotal(data.total);
    setLoading(false);
  }

  useEffect(() => { loadTasks(); }, [query, status, priority, page, limit, sort, order]);

  async function toggleStatus(task) {
    const updated = { status: task.status === 'Completed' ? 'Pending' : 'Completed' };
    await api.put(`/tasks/${task._id}`, updated);
    loadTasks();
  }

  async function deleteTask(task) {
    await api.delete(`/tasks/${task._id}`);
    loadTasks();
  }

  const totalPages = Math.max(1, Math.ceil(total / limit));

  if (loading) return <div className="text-gray-300 text-center py-8">Loading...</div>;

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="text-center mb-8">
        <h1 className="text-4xl font-bold mb-2">
          <span className="bg-gradient-to-r from-blue-400 via-purple-400 to-pink-400 bg-clip-text text-transparent">
            Your Tasks
          </span>
        </h1>
        <p className="text-gray-300 text-lg">Manage and organize your daily tasks</p>
      </div>

      {/* Filters Toolbar */}
      <div className="backdrop-blur-xl bg-black/20 border border-white/10 rounded-2xl p-6 shadow-xl">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <input
            placeholder="Search tasks..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-3 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-transparent"
          />
          <select
            value={status}
            onChange={(e) => setStatus(e.target.value)}
            className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-transparent"
          >
            <option value="all" className="bg-gray-800 text-white">All statuses</option>
            <option value="pending" className="bg-gray-800 text-white">Pending</option>
            <option value="completed" className="bg-gray-800 text-white">Completed</option>
          </select>
          <select
            value={priority}
            onChange={(e) => setPriority(e.target.value)}
            className="w-full bg-white/10 border border-white/20 rounded-xl px-4 py-3 text-white focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-transparent"
          >
            <option value="all" className="bg-gray-800 text-white">All priorities</option>
            <option value="low" className="bg-gray-800 text-white">Low</option>
            <option value="medium" className="bg-gray-800 text-white">Medium</option>
            <option value="high" className="bg-gray-800 text-white">High</option>
          </select>
        </div>
      </div>

      {/* Tasks Grid */}
      <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3">
        {items.map((t) => (
          <TaskCard key={t._id} task={t} onToggle={toggleStatus} onDelete={deleteTask} />
        ))}
        {items.length === 0 && (
          <div className="col-span-full text-center text-gray-300 py-12">
            <div className="text-6xl mb-4">📝</div>
            <div className="text-xl font-medium">No tasks found</div>
            <div className="text-gray-400">Create your first task to get started</div>
          </div>
        )}
      </div>

      {/* Pagination and Controls */}
      <div className="backdrop-blur-xl bg-black/20 border border-white/10 rounded-2xl p-6 shadow-xl">
        <div className="flex items-center justify-between gap-4">
          <div className="text-gray-300">
            Page {page} of {totalPages} • {total} items
          </div>
          
          <div className="flex items-center gap-3">
            <button
              className="px-4 py-2 bg-white/10 border border-white/20 text-white rounded-xl hover:bg-white/20 disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-200"
              onClick={() => setPage((p) => Math.max(1, p - 1))}
              disabled={page <= 1}
            >
              ← Previous
            </button>
            
            <button
              className="px-4 py-2 bg-white/10 border border-white/20 text-white rounded-xl hover:bg-white/20 disabled:opacity-50 disabled:cursor-not-allowed transition-all duration-200"
              onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
              disabled={page >= totalPages}
            >
              Next →
            </button>
            
            <select
              value={sort}
              onChange={(e) => setSort(e.target.value)}
              className="bg-white/10 border border-white/20 text-white rounded-xl px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-transparent"
            >
              <option value="createdAt" className="bg-gray-800 text-white">Created</option>
              <option value="dueDate" className="bg-gray-800 text-white">Due date</option>
              <option value="priority" className="bg-gray-800 text-white">Priority</option>
            </select>
            
            <select
              value={order}
              onChange={(e) => setOrder(e.target.value)}
              className="bg-white/10 border border-white/20 text-white rounded-xl px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-transparent"
            >
              <option value="desc" className="bg-gray-800 text-white">↓ Desc</option>
              <option value="asc" className="bg-gray-800 text-white">↑ Asc</option>
            </select>
          </div>
        </div>
      </div>
    </div>
  );
}
